}

chapters.correction:
public class Main {
    static int comptePairs(int[] t) {
        int c = 0;
        for (int x : t) { if (x % 2 == 0) c++; }
        return c;
    }
    public static void main(String[] args) {
        int[] t = {1, 2, 3, 4};
        System.out.println(comptePairs(t));
    }
}

